import{_ as t,c as i,o as s,a1 as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Avertissement ToS : Risques de compte et pratiques de sécurité | Antigravity Auth","description":"Apprenez les risques d'utilisation du plugin Antigravity Auth et les pratiques de sécurité des comptes. Comprenez les scénarios à haut risque, les mécanismes de shadow ban et les différences de limitation de débit, maîtrisez les stratégies multi-comptes, le contrôle d'utilisation et les méthodes de préchauffage des comptes.","frontmatter":{"title":"Avertissement ToS : Risques de compte et pratiques de sécurité | Antigravity Auth","sidebarTitle":"Évitez le bannissement","subtitle":"Avertissement ToS : Risques de compte et pratiques de sécurité","description":"Apprenez les risques d'utilisation du plugin Antigravity Auth et les pratiques de sécurité des comptes. Comprenez les scénarios à haut risque, les mécanismes de shadow ban et les différences de limitation de débit, maîtrisez les stratégies multi-comptes, le contrôle d'utilisation et les méthodes de préchauffage des comptes.","tags":["FAQ","Avertissement de risque","Sécurité des comptes"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"fr/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"fr/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}`),o={name:"fr/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function r(a,e,l,u,d,c){return s(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="avertissement-tos" tabindex="-1">Avertissement ToS <a class="header-anchor" href="#avertissement-tos" aria-label="Permalink to &quot;Avertissement ToS&quot;">​</a></h1><p>Après ce cours, vous comprendrez les risques potentiels liés à l&#39;utilisation du plugin Antigravity Auth et comment protéger la sécurité de votre compte Google.</p><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><p>Vous envisagez d&#39;utiliser le plugin Antigravity Auth pour accéder aux modèles d&#39;IA de Google Antigravity, mais vous avez quelques inquiétudes :</p><ul><li>Vous avez vu des rapports communautaires de comptes bannis ou shadow-bannis</li><li>Vous craignez que l&#39;utilisation d&#39;outils non officiels viole les conditions de service de Google</li><li>Vous ne savez pas si vous devez utiliser un nouveau compte ou un ancien compte</li><li>Vous voulez savoir comment réduire les risques</li></ul><p>Ces préoccupations sont légitimes. L&#39;utilisation de tout outil non officiel comporte certains risques, et cet article vous aidera à comprendre les points de risque spécifiques et les stratégies d&#39;atténuation.</p><h2 id="quand-consulter-ce-cours" tabindex="-1">Quand consulter ce cours <a class="header-anchor" href="#quand-consulter-ce-cours" aria-label="Permalink to &quot;Quand consulter ce cours&quot;">​</a></h2><ul><li><strong>Avant d&#39;installer le plugin</strong> : Comprendre les risques avant de décider d&#39;utiliser</li><li><strong>Lors du choix du compte</strong> : Décider quel compte Google utiliser pour l&#39;authentification</li><li><strong>En cas de bannissement</strong> : Comprendre les causes possibles et les mesures préventives</li><li><strong>Lors de l&#39;inscription d&#39;un nouveau compte</strong> : Éviter les modèles d&#39;utilisation à haut risque</li></ul><hr><h2 id="apercu-des-risques-principaux" tabindex="-1">Aperçu des risques principaux <a class="header-anchor" href="#apercu-des-risques-principaux" aria-label="Permalink to &quot;Aperçu des risques principaux&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Avertissement important</p><p><strong>L&#39;utilisation de ce plugin peut violer les conditions de service (Terms of Service) de Google.</strong></p><p>Un petit nombre d&#39;utilisateurs ont signalé que leurs comptes Google ont été bannis ou shadow-bannis (Shadow Ban, c&#39;est-à-dire restriction d&#39;accès sans notification explicite).</p><p><strong>L&#39;utilisation de ce plugin signifie que vous acceptez les déclarations suivantes :</strong></p><ol><li>Il s&#39;agit d&#39;un outil non officiel, non approuvé ou endossé par Google</li><li>Votre compte Google peut être suspendu ou banni définitivement</li><li>Vous assumez tous les risques et conséquences de l&#39;utilisation de ce plugin</li></ol></div><h3 id="qu-est-ce-qu-un-shadow-ban" tabindex="-1">Qu&#39;est-ce qu&#39;un shadow ban ? <a class="header-anchor" href="#qu-est-ce-qu-un-shadow-ban" aria-label="Permalink to &quot;Qu&#39;est-ce qu&#39;un shadow ban ?&quot;">​</a></h3><p><strong>Le shadow ban (Shadow Ban)</strong> est une mesure restrictive que Google applique aux comptes suspects. Contrairement au bannissement direct, le shadow ban n&#39;affiche pas de message d&#39;erreur explicite, mais plutôt :</p><ul><li>Les requêtes API retournent des erreurs 403 ou 429</li><li>Le quota s&#39;affiche comme disponible, mais ne peut pas être utilisé en réalité</li><li>Les autres comptes fonctionnent normalement, seul le compte marqué est affecté</li></ul><p>Le shadow ban dure généralement longtemps (de quelques jours à quelques semaines) et ne peut pas être récupéré par appel.</p><hr><h2 id="scenarios-a-haut-risque" tabindex="-1">Scénarios à haut risque <a class="header-anchor" href="#scenarios-a-haut-risque" aria-label="Permalink to &quot;Scénarios à haut risque&quot;">​</a></h2><p>Les scénarios suivants augmentent considérablement le risque de marquage ou de bannissement du compte :</p><h3 id="🚨-scenario-1-compte-google-tout-neuf" tabindex="-1">🚨 Scénario 1 : Compte Google tout neuf <a class="header-anchor" href="#🚨-scenario-1-compte-google-tout-neuf" aria-label="Permalink to &quot;🚨 Scénario 1 : Compte Google tout neuf&quot;">​</a></h3><p><strong>Niveau de risque : Extrêmement élevé</strong></p><p>Les comptes Google nouvellement enregistrés utilisant ce plugin ont une très forte probabilité d&#39;être bannis. Raisons :</p><ul><li>Les nouveaux comptes manquent de données d&#39;historique comportemental, faciles à marquer par le système de détection d&#39;abus de Google</li><li>Un grand nombre d&#39;appels API sur un nouveau compte sera considéré comme un comportement anormal</li><li>Google applique un examen plus strict sur les nouveaux comptes</li></ul><p><strong>Recommandation</strong> : Ne créez pas de nouveau compte spécifiquement pour ce plugin.</p><h3 id="🚨-scenario-2-nouveau-compte-abonnement-pro-ultra" tabindex="-1">🚨 Scénario 2 : Nouveau compte + Abonnement Pro/Ultra <a class="header-anchor" href="#🚨-scenario-2-nouveau-compte-abonnement-pro-ultra" aria-label="Permalink to &quot;🚨 Scénario 2 : Nouveau compte + Abonnement Pro/Ultra&quot;">​</a></h3><p><strong>Niveau de risque : Extrêmement élevé</strong></p><p>Les comptes nouvellement enregistrés qui s&#39;abonnent immédiatement aux services Pro ou Ultra de Google sont souvent marqués et bannis. Raisons :</p><ul><li>Le modèle d&#39;utilisation élevée après l&#39;abonnement sur un nouveau compte ressemble à un abus</li><li>Google applique un examen plus strict sur les nouveaux utilisateurs payants</li><li>Ce modèle diffère trop du parcours de croissance d&#39;un utilisateur normal</li></ul><p><strong>Recommandation</strong> : Laissez le compte &quot;croître naturellement&quot; pendant un certain temps (au moins quelques mois) avant d&#39;envisager un abonnement.</p><h3 id="🟡-scenario-3-grand-nombre-de-requetes-en-peu-de-temps" tabindex="-1">🟡 Scénario 3 : Grand nombre de requêtes en peu de temps <a class="header-anchor" href="#🟡-scenario-3-grand-nombre-de-requetes-en-peu-de-temps" aria-label="Permalink to &quot;🟡 Scénario 3 : Grand nombre de requêtes en peu de temps&quot;">​</a></h3><p><strong>Niveau de risque : Élevé</strong></p><p>Lancer un grand nombre de requêtes API en peu de temps, ou utiliser fréquemment des proxies parallèles/sessions multiples, déclenchera la limitation de débit et la détection d&#39;abus. Raisons :</p><ul><li>Le modèle de requêtes d&#39;OpenCode est plus dense que les applications natives (appels d&#39;outils, tentatives, streaming, etc.)</li><li>Les requêtes hautement concurrentes déclenchent les mécanismes de protection de Google</li></ul><p><strong>Recommandations</strong> :</p><ul><li>Contrôler la fréquence des requêtes et le nombre de connexions concurrentes</li><li>Éviter de lancer plusieurs proxies parallèles simultanément</li><li>Utiliser la rotation multi-comptes pour disperser les requêtes</li></ul><h3 id="🟡-scenario-4-utilisation-d-un-compte-google-unique" tabindex="-1">🟡 Scénario 4 : Utilisation d&#39;un compte Google unique <a class="header-anchor" href="#🟡-scenario-4-utilisation-d-un-compte-google-unique" aria-label="Permalink to &quot;🟡 Scénario 4 : Utilisation d&#39;un compte Google unique&quot;">​</a></h3><p><strong>Niveau de risque : Moyen</strong></p><p>Si vous n&#39;avez qu&#39;un seul compte Google et que vous en dépendez pour accéder aux services critiques (Gmail, Drive, etc.), le risque est plus élevé. Raisons :</p><ul><li>Le bannissement du compte affectera votre travail quotidien</li><li>Impossible de récupérer par appel</li><li>Absence de solution de secours</li></ul><p><strong>Recommandation</strong> : Utilisez un compte indépendant qui ne dépend pas de services critiques.</p><hr><h2 id="recommandations-de-meilleures-pratiques" tabindex="-1">Recommandations de meilleures pratiques <a class="header-anchor" href="#recommandations-de-meilleures-pratiques" aria-label="Permalink to &quot;Recommandations de meilleures pratiques&quot;">​</a></h2><h3 id="✅-pratiques-recommandees" tabindex="-1">✅ Pratiques recommandées <a class="header-anchor" href="#✅-pratiques-recommandees" aria-label="Permalink to &quot;✅ Pratiques recommandées&quot;">​</a></h3><p><strong>1. Utiliser un compte Google établi</strong></p><p>Privilégiez un compte Google utilisé depuis un certain temps (recommandé 6 mois ou plus) :</p><ul><li>Avec un historique d&#39;utilisation normale des services Google (Gmail, Drive, Google Search, etc.)</li><li>Sans antécédents de violation</li><li>Compte lié à un numéro de téléphone et vérifié</li></ul><p><strong>2. Configurer plusieurs comptes</strong></p><p>Ajoutez plusieurs comptes Google, dispersez les requêtes par rotation :</p><ul><li>Configurez au moins 2-3 comptes</li><li>Utilisez la stratégie <code>account_selection_strategy: &quot;hybrid&quot;</code> (par défaut)</li><li>Basculez automatiquement entre les comptes en cas de limitation de débit</li></ul><p><strong>3. Contrôler le volume d&#39;utilisation</strong></p><ul><li>Évitez les requêtes intensives en peu de temps</li><li>Réduisez le nombre de proxies parallèles</li><li>Définissez <code>max_rate_limit_wait_seconds: 0</code> dans <code>antigravity.json</code> pour échouer rapidement plutôt que de réessayer</li></ul><p><strong>4. Surveiller l&#39;état des comptes</strong></p><p>Vérifiez régulièrement l&#39;état des comptes :</p><ul><li>Consultez <code>rateLimitResetTimes</code> dans <code>~/.config/opencode/antigravity-accounts.json</code></li><li>Activez les journaux de débogage : <code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>En cas d&#39;erreurs 403/429, suspendez l&#39;utilisation pendant 24-48 heures</li></ul><p><strong>5. &quot;Préchauffer&quot; d&#39;abord dans l&#39;interface officielle</strong></p><p>Méthode efficace rapportée par la communauté :</p><ol><li>Connectez-vous à <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> dans le navigateur</li><li>Exécutez quelques invites simples (comme « Bonjour », « Combien font 2+2 »)</li><li>Après 5-10 appels réussis, utilisez le plugin</li></ol><p><strong>Principe</strong> : L&#39;utilisation du compte via l&#39;interface officielle fait croire à Google qu&#39;il s&#39;agit d&#39;un comportement d&#39;utilisateur normal, réduisant le risque de marquage.</p><h3 id="❌-pratiques-a-eviter" tabindex="-1">❌ Pratiques à éviter <a class="header-anchor" href="#❌-pratiques-a-eviter" aria-label="Permalink to &quot;❌ Pratiques à éviter&quot;">​</a></h3><ul><li>❌ Créer un nouveau compte Google spécifiquement pour ce plugin</li><li>❌ S&#39;abonner immédiatement à Pro/Ultra sur un compte nouvellement enregistré</li><li>❌ Utiliser votre unique compte de services critiques (comme l&#39;email professionnel)</li><li>❌ Réessayer de manière répétée après avoir déclenché une limitation 429</li><li>❌ Lancer un grand nombre de proxies parallèles simultanément</li><li>❌ Soumettre <code>antigravity-accounts.json</code> au contrôle de version</li></ul><hr><h2 id="questions-frequentes" tabindex="-1">Questions fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions fréquentes&quot;">​</a></h2><h3 id="q-mon-compte-a-ete-banni-puis-je-faire-appel" tabindex="-1">Q : Mon compte a été banni, puis-je faire appel ? <a class="header-anchor" href="#q-mon-compte-a-ete-banni-puis-je-faire-appel" aria-label="Permalink to &quot;Q : Mon compte a été banni, puis-je faire appel ?&quot;">​</a></h3><p><strong>R : Non.</strong></p><p>Si le bannissement ou le shadow ban est déclenché par la détection d&#39;abus de Google via ce plugin, il est généralement impossible de récupérer par appel. Raisons :</p><ul><li>Le bannissement est déclenché automatiquement en fonction du modèle d&#39;utilisation de l&#39;API</li><li>Google adopte une attitude stricte envers l&#39;utilisation d&#39;outils non officiels</li><li>L&#39;appel nécessite d&#39;expliquer l&#39;utilisation de l&#39;outil, mais ce plugin lui-même peut être considéré comme une violation</li></ul><p><strong>Recommandations</strong> :</p><ul><li>Utilisez d&#39;autres comptes non affectés</li><li>Si tous les comptes sont bannis, utilisez directement <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>Évitez de continuer à essayer sur les comptes bannis</li></ul><h3 id="q-l-utilisation-de-ce-plugin-entrainera-t-elle-forcement-un-bannissement" tabindex="-1">Q : L&#39;utilisation de ce plugin entraînera-t-elle forcément un bannissement ? <a class="header-anchor" href="#q-l-utilisation-de-ce-plugin-entrainera-t-elle-forcement-un-bannissement" aria-label="Permalink to &quot;Q : L&#39;utilisation de ce plugin entraînera-t-elle forcément un bannissement ?&quot;">​</a></h3><p><strong>R : Pas nécessairement.</strong></p><p>La plupart des utilisateurs n&#39;ont rencontré aucun problème en utilisant ce plugin. Le risque dépend de :</p><ul><li>L&#39;âge du compte et l&#39;historique comportemental</li><li>La fréquence d&#39;utilisation et le modèle de requêtes</li><li>Le respect des meilleures pratiques</li></ul><p><strong>Évaluation des risques</strong> :</p><ul><li>Ancien compte + utilisation modérée + rotation multi-comptes → Risque faible</li><li>Nouveau compte + requêtes intensives + compte unique → Risque élevé</li></ul><h3 id="q-quelle-est-la-difference-entre-shadow-ban-et-limitation-de-debit" tabindex="-1">Q : Quelle est la différence entre shadow ban et limitation de débit ? <a class="header-anchor" href="#q-quelle-est-la-difference-entre-shadow-ban-et-limitation-de-debit" aria-label="Permalink to &quot;Q : Quelle est la différence entre shadow ban et limitation de débit ?&quot;">​</a></h3><p><strong>R : Nature différente, méthodes de récupération différentes.</strong></p><table tabindex="0"><thead><tr><th>Caractéristique</th><th>Shadow Ban</th><th>Limitation de débit (429)</th></tr></thead><tbody><tr><td>Cause du déclenchement</td><td>Détection d&#39;abus, marqué comme suspect</td><td>Fréquence de requêtes dépassant le quota</td></tr><tr><td>Code d&#39;erreur</td><td>403 ou échec silencieux</td><td>429 Too Many Requests</td></tr><tr><td>Durée</td><td>Quelques jours à quelques semaines</td><td>Quelques heures à un jour</td></tr><tr><td>Méthode de récupération</td><td>Impossible à récupérer, utiliser un autre compte</td><td>Attendre la réinitialisation ou changer de compte</td></tr><tr><td>Peut-on prévenir</td><td>Suivre les meilleures pratiques pour réduire le risque</td><td>Contrôler la fréquence des requêtes</td></tr></tbody></table><h3 id="q-puis-je-utiliser-un-compte-google-d-entreprise" tabindex="-1">Q : Puis-je utiliser un compte Google d&#39;entreprise ? <a class="header-anchor" href="#q-puis-je-utiliser-un-compte-google-d-entreprise" aria-label="Permalink to &quot;Q : Puis-je utiliser un compte Google d&#39;entreprise ?&quot;">​</a></h3><p><strong>R : Non recommandé.</strong></p><p>Les comptes d&#39;entreprise sont généralement liés à des services et données critiques, le bannissement a un impact plus grave. De plus :</p><ul><li>Les comptes d&#39;entreprise font l&#39;objet d&#39;un examen plus strict</li><li>Peut violer la politique informatique de l&#39;entreprise</li><li>Le risque est assumé individuellement, mais affecte l&#39;équipe</li></ul><p><strong>Recommandation</strong> : Utilisez un compte personnel.</p><h3 id="q-les-comptes-multiples-peuvent-ils-eviter-completement-le-bannissement" tabindex="-1">Q : Les comptes multiples peuvent-ils éviter complètement le bannissement ? <a class="header-anchor" href="#q-les-comptes-multiples-peuvent-ils-eviter-completement-le-bannissement" aria-label="Permalink to &quot;Q : Les comptes multiples peuvent-ils éviter complètement le bannissement ?&quot;">​</a></h3><p><strong>R : Impossible d&#39;éviter complètement, mais peut réduire l&#39;impact.</strong></p><p>Rôle des comptes multiples :</p><ul><li>Disperser les requêtes, réduire la probabilité qu&#39;un seul compte déclenche une limitation</li><li>Si un compte est banni, les autres comptes restent utilisables</li><li>Basculer automatiquement en cas de limitation, améliorer la disponibilité</li></ul><p><strong>Mais les comptes multiples ne sont pas un &quot;talisman&quot;</strong> :</p><ul><li>Si tous les comptes déclenchent la détection d&#39;abus, ils peuvent tous être bannis</li><li>Ne pas abuser des comptes multiples pour des requêtes intensives</li><li>Chaque compte doit toujours suivre les meilleures pratiques</li></ul><hr><h2 id="points-de-controle-✅" tabindex="-1">Points de contrôle ✅ <a class="header-anchor" href="#points-de-controle-✅" aria-label="Permalink to &quot;Points de contrôle ✅&quot;">​</a></h2><p>Après avoir lu ce cours, vous devriez savoir :</p><ul><li>[ ] L&#39;utilisation de ce plugin peut violer les ToS de Google, risques à vos propres frais</li><li>[ ] Nouveau compte + abonnement Pro/Ultra est un scénario à haut risque</li><li>[ ] Il est recommandé d&#39;utiliser un compte Google établi</li><li>[ ] Configurer plusieurs comptes peut disperser les risques</li><li>[ ] Les comptes bannis ne peuvent pas être récupérés par appel</li><li>[ ] Contrôler la fréquence des requêtes et le volume d&#39;utilisation est important</li></ul><hr><h2 id="resume-de-ce-cours" tabindex="-1">Résumé de ce cours <a class="header-anchor" href="#resume-de-ce-cours" aria-label="Permalink to &quot;Résumé de ce cours&quot;">​</a></h2><p>Ce cours a présenté les risques potentiels liés à l&#39;utilisation du plugin Antigravity Auth :</p><ol><li><strong>Risques principaux</strong> : Peut violer les ToS de Google, le compte peut être banni ou shadow-banni</li><li><strong>Scénarios à haut risque</strong> : Nouveau compte, nouveau compte + abonnement, requêtes intensives, compte critique unique</li><li><strong>Meilleures pratiques</strong> : Utiliser un ancien compte, configurer plusieurs comptes, contrôler le volume d&#39;utilisation, surveiller l&#39;état, &quot;préchauffer&quot; d&#39;abord</li><li><strong>Questions fréquentes</strong> : Impossible de faire appel, les risques varient selon les personnes, les comptes multiples peuvent réduire l&#39;impact</li></ol><p>Avant d&#39;utiliser ce plugin, veuillez évaluer soigneusement les risques. Si vous ne pouvez pas accepter les conséquences d&#39;un éventuel bannissement de compte, il est recommandé d&#39;utiliser directement <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>.</p><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquer pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-23</p></blockquote><p>Ce cours est basé sur la section d&#39;avertissement de risque du document README du projet (README.md:23-40), sans impliquer d&#39;implémentation de code spécifique.</p><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Déclaration d&#39;avertissement ToS</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const q=t(o,[["render",r]]);export{m as __pageData,q as default};
